class Solution:
	def solve(self, nums: list[int], target: int) -> bool:
		if nums: 
			left, right = 0, len(nums) - 1
			while left <= right:
				mid = (left + right) // 2
				if nums[mid] == target:
					return True
				elif nums[mid] < target:
					left = mid + 1
				else:
					right = mid - 1
			return False

