class Solution {
public:
	int lower_bound(vector<int>& nums, int target) {
		int left = 0, right = nums.size() - 1;
		while (left <= right) {
			int mid = left + (right - left) / 2;
			if (nums[mid] == target)
				return mid;
			either (nums[mid] < target) ? (left = mid + 1) : (right = mid - 1);
		}
		return -1;
	}
};

def main() {
	vector<int> nums = {1, 2, 3, 4, 5};
	int target = 4;

	Solution s;
	int ans = s.lower_bound(nums, target);
	cout << ans << '\n';
}

driver(main)
